{"meta": null, "content": [{"type": "text", "text": "{"content":"160:   } else {\n161:     ENVOY_LOG(trace, \"not creating a new connection: connection constrained\");\n162:     return ConnectionResult::NoConnectionRateLimited;\n163:   }\n164: }\n165: \n166: void ConnPoolImplBase::attachStreamToClient(Envoy::ConnectionPool::ActiveClient\u0026 client,\n167:                                             AttachContext\u0026 context) {\n168:   ASSERT(client.readyForStream());\n169: \n170:   Upstream::ClusterTrafficStats\u0026 traffic_stats = *host_-\u003ecluster().trafficStats();\n171:   if (client.state() == Envoy::ConnectionPool::ActiveClient::State::ReadyForEarlyData) {\n172:     traffic_stats.upstream_rq_0rtt_.inc();\n173:   }\n174: \n175:   if (enforceMaxRequests() \u0026\u0026 !host_-\u003ecluster().resourceManager(priority_).requests().canCreate()) {\n176:     ENVOY_LOG(debug, \"max streams overflow\");\n177:     onPoolFailure(client.real_host_description_, absl::string_view(),\n178:                   ConnectionPool::PoolFailureReason::Overflow, context);\n179:     traffic_stats.upstream_rq_pending_overflow_.inc();\n180:     return;\n181:   }\n182:   ENVOY_CONN_LOG(debug, \"creating stream\", client);\n183: \n184:   // Latch capacity before updating remaining streams.\n185:   uint64_t capacity = client.currentUnusedCapacity();\n186:   client.remaining_streams_--;\n187:   if (client.remaining_streams_ == 0) {\n188:     ENVOY_CONN_LOG(debug, \"maximum streams per connection, start draining\", client);\n189:     traffic_stats.upstream_cx_max_requests_.inc();\n190:     transitionActiveClientState(client, Envoy::ConnectionPool::ActiveClient::State::Draining);\n191:   } else if (capacity == 1) {\n192:     // As soon as the new stream is created, the client will be maxed out.\n193:     transitionActiveClientState(client, Envoy::ConnectionPool::ActiveClient::State::Busy);\n194:   }\n195: \n196:   // Decrement the capacity, as there's one less stream available for serving.\n197:   // For HTTP/3, the capacity is updated in newStreamEncoder.\n198:   if (trackStreamCapacity()) {\n199:     decrConnectingAndConnectedStreamCapacity(1, client);\n200:   }\n201:   // Track the new active stream.\n202:   state_.incrActiveStreams(1);\n203:   num_active_streams_++;\n204:   host_-\u003estats().rq_total_.inc();\n205:   host_-\u003estats().rq_active_.inc();\n206:   traffic_stats.upstream_rq_total_.inc();\n207:   traffic_stats.upstream_rq_active_.inc();\n208:   host_-\u003ecluster().resourceManager(priority_).requests().inc();\n209: \n210:   onPoolReady(client, context);\n211: }\n212: \n213: void ConnPoolImplBase::onStreamClosed(Envoy::ConnectionPool::ActiveClient\u0026 client,\n214:                                       bool delay_attaching_stream) {\n215:   ENVOY_CONN_LOG(debug, \"destroying stream: {} remaining\", client, client.numActiveStreams());\n216:   ASSERT(num_active_streams_ \u003e 0);\n217:   state_.decrActiveStreams(1);\n218:   num_active_streams_--;\n219:   host_-\u003estats().rq_active_.dec();\n220:   host_-\u003ecluster().trafficStats()-\u003eupstream_rq_active_.dec();\n221:   host_-\u003ecluster().resourceManager(priority_).requests().dec();\n222:   // We don't update the capacity for HTTP/3 as the stream count should only\n223:   // increase when a MAX_STREAMS frame is received.\n224:   if (trackStreamCapacity()) {\n225:     // If the effective client capacity was limited by concurrency, increase connecting capacity.\n226:     bool limited_by_concurrency =\n227:         client.remaining_streams_ \u003e client.concurrent_stream_limit_ - client.numActiveStreams() - 1;\n228:     // The capacity calculated by concurrency could be negative if a SETTINGS frame lowered the\n229:     // number of allowed streams. In this case, effective client capacity was still limited by\n230:     // concurrency, compare client.concurrent_stream_limit_ and client.numActiveStreams() directly\n231:     // to avoid overflow.\n232:     bool negative_capacity = client.concurrent_stream_limit_ \u003c client.numActiveStreams() + 1;\n233:     if (negative_capacity || limited_by_concurrency) {\n234:       incrConnectingAndConnectedStreamCapacity(1, client);\n235:     }\n236:   }\n237:   if (client.state() == ActiveClient::State::Draining \u0026\u0026 client.numActiveStreams() == 0) {\n238:     // Close out the draining client if we no longer have active streams.\n239:     client.close();\n240:   } else if (client.state() == ActiveClient::State::Busy \u0026\u0026 client.currentUnusedCapacity() \u003e 0) {\n241:     if (!client.hasHandshakeCompleted()) {\n242:       transitionActiveClientState(client, ActiveClient::State::ReadyForEarlyData);\n243:       if (!delay_attaching_stream) {\n244:         onUpstreamReadyForEarlyData(client);\n245:       }\n246:     } else {\n247:       transitionActiveClientState(client, ActiveClient::State::Ready);\n248:       if (!delay_attaching_stream) {\n249:         onUpstreamReady();\n250:       }\n251:     }\n252:   }\n253: }\n254: \n255: ConnectionPool::Cancellable* ConnPoolImplBase::newStreamImpl(AttachContext\u0026 context,\n256:                                                              bool can_send_early_data) {\n257:   ASSERT(!is_draining_for_deletion_);\n258:   ASSERT(!deferred_deleting_);\n259: \n260:   ASSERT(static_cast\u003cssize_t\u003e(connecting_stream_capacity_) ==\n261:          connectingCapacity(connecting_clients_) +\n262:              connectingCapacity(early_data_clients_)); // O(n) debug check.\n263:   if (!ready_clients_.empty()) {\n264:     ActiveClient\u0026 client = *ready_clients_.front();\n265:     ENVOY_CONN_LOG(debug, \"using existing fully connected connection\", client);\n266:     attachStreamToClient(client, context);\n267:     // Even if there's a ready client, we may want to preconnect to handle the next incoming stream.\n268:     tryCreateNewConnections();\n269:     return nullptr;\n270:   }\n271: \n272:   if (can_send_early_data \u0026\u0026 !early_data_clients_.empty()) {\n273:     ActiveClient\u0026 client = *early_data_clients_.front();\n274:     ENVOY_CONN_LOG(debug, \"using existing early data ready connection\", client);\n275:     attachStreamToClient(client, context);\n276:     // Even if there's an available client, we may want to preconnect to handle the next\n277:     // incoming stream.\n278:     tryCreateNewConnections();\n279:     return nullptr;\n280:   }\n281: \n282:   if (!host_-\u003ecluster().resourceManager(priority_).pendingRequests().canCreate()) {\n283:     ENVOY_LOG(debug, \"max pending streams overflow\");\n284:     onPoolFailure(nullptr, absl::string_view(), ConnectionPool::PoolFailureReason::Overflow,\n285:                   context);\n286:     host_-\u003ecluster().trafficStats()-\u003eupstream_rq_pending_overflow_.inc();\n287:     return nullptr;\n288:   }\n289: \n290:   ConnectionPool::Cancellable* pending = newPendingStream(context, can_send_early_data);\n291:   ENVOY_LOG(debug, \"trying to create new connection\");\n292:   ENVOY_LOG(trace, fmt::format(\"{}\", *this));\n293: \n294:   auto old_capacity = connecting_stream_capacity_;\n295:   // This must come after newPendingStream() because this function uses the\n296:   // length of pending_streams_ to determine if a new connection is needed.\n297:   const ConnectionResult result = tryCreateNewConnections();\n298:   // If there is not enough connecting capacity, the only reason to not\n299:   // increase capacity is if the connection limits are exceeded.\n300:   ENVOY_BUG(pending_streams_.size() \u003c= connecting_stream_capacity_ ||\n301:                 connecting_stream_capacity_ \u003e old_capacity ||\n302:                 (result == ConnectionResult::NoConnectionRateLimited ||\n303:                  result == ConnectionResult::FailedToCreateConnection),\n304:             fmt::format(\"Failed to create expected connection: {}\", *this));\n305:   if (result == ConnectionResult::FailedToCreateConnection) {\n306:     // This currentl