112: // Adjust the concurrent stream limit if the negotiated concurrent stream limit
113: // is lower than the local max configured streams.
114: //
115: // Note: if multiple streams are assigned to a connection before the settings
116: // are received, they may still be reset by the peer. This could be avoided by
117: // not considering http/2 connections connected until the SETTINGS frame is
118: // received, but that would result in a latency penalty instead.
119: void MultiplexedActiveClientBase::onSettings(ReceivedSettings& settings) {
120:   if (settings.maxConcurrentStreams().has_value()) {
121:     int64_t old_unused_capacity = currentUnusedCapacity();
122:     // Given config limits old_unused_capacity should never exceed int32_t.
123:     ASSERT(std::numeric_limits<int32_t>::max() >= old_unused_capacity);
124:     if (parent().cache() && parent().origin().has_value()) {
125:       parent().cache()->setConcurrentStreams(*parent().origin(),
126:                                              settings.maxConcurrentStreams().value());
127:     }
128:     concurrent_stream_limit_ =
129:         std::min(settings.maxConcurrentStreams().value(), configured_stream_limit_);
130: 
131:     int64_t delta = old_unused_capacity - currentUnusedCapacity();
132:     if (state() == ActiveClient::State::Ready && currentUnusedCapacity() <= 0) {
133:       parent_.transitionActiveClientState(*this, ActiveClient::State::Busy);
134:     } else if (state() == ActiveClient::State::Busy && currentUnusedCapacity() > 0) {
135:       parent_.transitionActiveClientState(*this, ActiveClient::State::Ready);
136:     }
137: 
138:     if (delta > 0) {
139:       parent_.decrClusterStreamCapacity(delta);
140:       ENVOY_CONN_LOG(trace, "Decreasing stream capacity by {}", *codec_client_, delta);
141:     } else if (delta < 0) {
142:       parent_.incrClusterStreamCapacity(-delta);
143:       ENVOY_CONN_LOG(trace, "Increasing stream capacity by {}", *codec_client_, -delta);
144:     }
145:   }
146: }
