148: void MultiplexedActiveClientBase::onStreamDestroy() {
149:   parent().onStreamClosed(*this, false);
150: 
151:   // If we are destroying this stream because of a disconnect, do not check for drain here. We will
152:   // wait until the connection has been fully drained of streams and then check in the connection
153:   // event callback.
154:   if (!closed_with_active_rq_) {
155:     parent().checkForIdleAndCloseIdleConnsIfDraining();
156:   }
157: }
