159: void MultiplexedActiveClientBase::onStreamReset(Http::StreamResetReason reason) {
160:   switch (reason) {
161:   case StreamResetReason::ConnectionTermination:
162:   case StreamResetReason::LocalConnectionFailure:
163:   case StreamResetReason::RemoteConnectionFailure:
164:   case StreamResetReason::ConnectionTimeout:
165:     parent_.host()->cluster().trafficStats()->upstream_rq_pending_failure_eject_.inc();
166:     closed_with_active_rq_ = true;
167:     break;
168:   case StreamResetReason::LocalReset:
169:   case StreamResetReason::ProtocolError:
170:   case StreamResetReason::OverloadManager:
171:     parent_.host()->cluster().trafficStats()->upstream_rq_tx_reset_.inc();
172:     break;
173:   case StreamResetReason::RemoteReset:
174:     parent_.host()->cluster().trafficStats()->upstream_rq_rx_reset_.inc();
175:     break;
176:   case StreamResetReason::LocalRefusedStreamReset:
177:   case StreamResetReason::RemoteRefusedStreamReset:
178:   case StreamResetReason::Overflow:
179:   case StreamResetReason::ConnectError:
180:     break;
181:   }
182: }
