1372: void Filter::onUpstreamReset(Http::StreamResetReason reset_reason,
1373:                              absl::string_view transport_failure_reason,
1374:                              UpstreamRequest& upstream_request) {
1375:   ENVOY_STREAM_LOG(debug, "upstream reset: reset reason: {}, transport failure reason: {}",
1376:                    *callbacks_, Http::Utility::resetReasonToString(reset_reason),
1377:                    transport_failure_reason);
1378: 
1379:   const bool dropped = reset_reason == Http::StreamResetReason::Overflow;
1380: 
1381:   // Ignore upstream reset caused by a resource overflow.
1382:   // Currently, circuit breakers can only produce this reset reason.
1383:   // It means that this reason is cluster-wise, not upstream-related.
1384:   // Therefore removing an upstream in the case of an overloaded cluster
1385:   // would make the situation even worse.
1386:   // https://github.com/envoyproxy/envoy/issues/25487
1387:   if (!dropped) {
1388:     // TODO: The reset may also come from upstream over the wire. In this case it should be
1389:     // treated as external origin error and distinguished from local origin error.
1390:     // This matters only when running OutlierDetection with split_external_local_origin_errors
1391:     // config param set to true.
1392:     updateOutlierDetection(Upstream::Outlier::Result::LocalOriginConnectFailed, upstream_request,
1393:                            absl::nullopt);
1394:   }
1395: 
1396:   if (maybeRetryReset(reset_reason, upstream_request, TimeoutRetry::No)) {
1397:     return;
1398:   }
1399: 
1400:   const Http::Code error_code = (reset_reason == Http::StreamResetReason::ProtocolError)
1401:                                     ? Http::Code::BadGateway
1402:                                     : Http::Code::ServiceUnavailable;
1403:   chargeUpstreamAbort(error_code, dropped, upstream_request);
1404:   auto request_ptr = upstream_request.removeFromList(upstream_requests_);
1405:   callbacks_->dispatcher().deferredDelete(std::move(request_ptr));
1406: 
1407:   // If there are other in-flight requests that might see an upstream response,
1408:   // don't return anything downstream.
1409:   if (numRequestsAwaitingHeaders() > 0 || pending_retries_ > 0) {
1410:     return;
1411:   }
1412: 
1413:   const StreamInfo::CoreResponseFlag response_flags = streamResetReasonToResponseFlag(reset_reason);
1414: 
1415:   const std::string body =
1416:       absl::StrCat("upstream connect error or disconnect/reset before headers. ",
1417:                    (is_retry_ ? "retried and the latest " : ""),
1418:                    "reset reason: ", Http::Utility::resetReasonToString(reset_reason),
1419:                    !transport_failure_reason.empty() ? ", transport failure reason: " : "",
1420:                    transport_failure_reason);
1421:   const std::string& basic_details =
1422:       downstream_response_started_ ? StreamInfo::ResponseCodeDetails::get().LateUpstreamReset
1423:                                    : StreamInfo::ResponseCodeDetails::get().EarlyUpstreamReset;
1424:   const std::string details = StringUtil::replaceAllEmptySpace(absl::StrCat(
1425:       basic_details, "{", Http::Utility::resetReasonToString(reset_reason),
1426:       transport_failure_reason.empty() ? "" : absl::StrCat("|", transport_failure_reason), "}"));
1427:   onUpstreamAbort(error_code, response_flags, body, dropped, details);
1428: }
